#include<bits/stdc++.h>
using namespace std;
char ch[3005];
int f[3005][3005],g[3005][3005],n,a[3005],ans;
int	main(void){
	cin>>n;
	for(int i=1;i<=n;i++){
        cin>>ch[i]>>a[i];
        a[n+i]=a[i];ch[n+i]=ch[i];
    }
    for(int i=1;i<=n*2;i++){
        for(int j=1;j<=n*2;j++){
            f[i][j]=-0x3f3f3f3f,g[i][j]=0x3f3f3f3f;
        }
    }
    for(int i=1;i<=(n<<1);i++)f[i][i]=g[i][i]=a[i];
	for(int len=2;len<=n;len++){
		for(int l=1;l+len-1<=2*n;l++){
			int r=l+len-1;
			for(int k=l+1;k<=r;k++)
				if(ch[k]=='t'){
					f[l][r]=max(f[l][r],f[l][k-1]+f[k][r]);
					g[l][r]=min(g[l][r],g[l][k-1]+g[k][r]);
				}else{
					f[l][r]=max(f[l][r],max(f[l][k-1]*f[k][r],g[l][k-1]*g[k][r]));
					g[l][r]=min(g[l][r],min(g[l][k-1]*g[k][r],min(f[l][k-1]*f[k][r],min(f[l][k-1]*g[k][r],g[l][k-1]*f[k][r]))));//min
				}
		}
	}
    for(int i=1;i<=n;i++)ans=max(ans,f[i][i+n-1]);cout<<ans<<'\n';
    for(int i=1;i<=n;i++)if(f[i][i+n-1]==ans)cout<<i<<' ';
	return	false;
}
